// Bicep: deploy core platform landing zone resources at subscription scope
// Deploy with: az deployment sub create --template-file platform-lz.bicep --location eastus

targetScope = 'subscription'

param location string = 'eastus'
param regionAbbr string = 'eastus'
param environment string = 'prod'

// 1. Create the connectivity resource group
resource rgConnectivity 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-connectivity-${environment}-${regionAbbr}'
  location: location
  tags: { Environment: environment, Application: 'connectivity' }
}

// 2. Deploy hub VNet into the connectivity RG
module hubVnet 'modules/hub-vnet.bicep' = {
  name: 'hub-vnet'
  scope: rgConnectivity
  params: {
    vnetName:      'vnet-hub-${environment}-${regionAbbr}'
    addressPrefix: '10.0.0.0/16'
    environment:   environment
    regionAbbr:    regionAbbr
  }
}

// 3. Deploy Azure Firewall
module firewall 'modules/firewall.bicep' = {
  name: 'firewall'
  scope: rgConnectivity
  dependsOn: [hubVnet]
  params: {
    fwName:    'afw-hub-${environment}-${regionAbbr}'
    vnetName:  hubVnet.outputs.vnetName
    pipName:   'pip-afw-hub-${environment}-${regionAbbr}'
  }
}

// 4. Deploy Private DNS zones for common Azure services
var privateDnsZones = [
  'privatelink.blob.core.windows.net'
  'privatelink.vaultcore.azure.net'
  'privatelink.database.windows.net'
  'privatelink.servicebus.windows.net'
  'privatelink.azurecr.io'
]

module dnsZones 'modules/private-dns.bicep' = [for zone in privateDnsZones: {
  name: 'dns-${replace(zone, '.', '-')}'
  scope: rgConnectivity
  params: {
    zoneName:    zone
    hubVnetId:   hubVnet.outputs.vnetId
    linkName:    'link-hub-${replace(zone, '.', '-')}'
  }
}]

output hubVnetId string = hubVnet.outputs.vnetId
output firewallPrivateIp string = firewall.outputs.privateIp

// Bicep: provision an application landing zone (spoke subscription)
// Called once per workload by the platform team

targetScope = 'subscription'

param workload string
param environment string = 'prod'
param location string = 'eastus'
param regionAbbr string = 'eastus'
param hubVnetId string          // resource ID of the hub VNet
param firewallIp string         // private IP of the hub Azure Firewall (for UDR)
param appTeamObjectId string    // AAD object ID of the application team group

// 1. Resource groups
resource rgNetwork 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-${workload}-network-${environment}-${regionAbbr}'
  location: location
  tags: { Environment: environment, Application: workload }
}

resource rgApp 'Microsoft.Resources/resourceGroups@2024-03-01' = {
  name: 'rg-${workload}-app-${environment}-${regionAbbr}'
  location: location
  tags: { Environment: environment, Application: workload }
}

// 2. Spoke VNet with standard subnet layout
module spokeVnet 'modules/spoke-vnet.bicep' = {
  name: 'spoke-vnet-${workload}'
  scope: rgNetwork
  params: {
    vnetName:     'vnet-${workload}-${environment}-${regionAbbr}'
    appSubnet:    'snet-${workload}-app-${environment}-${regionAbbr}'
    dataSubnet:   'snet-${workload}-data-${environment}-${regionAbbr}'
    firewallIp:   firewallIp
  }
}

// 3. VNet peering: spoke -> hub
module spokePeering 'modules/vnet-peering.bicep' = {
  name: 'peering-spoke-to-hub'
  scope: rgNetwork
  params: {
    localVnetName:   spokeVnet.outputs.vnetName
    peeringName:     'peer-${workload}-to-hub'
    remoteVnetId:    hubVnetId
    useRemoteGateways: true
  }
}

// 4. Grant the app team Contributor on the subscription
resource appTeamContributor 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(subscription().id, appTeamObjectId, 'Contributor')
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', 'b24988ac-6180-42a0-ab88-20f7382dd24c')
    principalId: appTeamObjectId
    principalType: 'Group'
  }
}

output spokeVnetId string = spokeVnet.outputs.vnetId
output appRg string = rgApp.name
